        if (dsu.unite(e[0], e[1])) {
            components--;
        }
    }

    if (components == 1) {
        long long min_s = LLONG_MAX;
        for (auto& e : must_edges) {
            min_s = min(min_s, e[2]);
        }
        return min_s;
    }

    sort(optional_edges.begin(), optional_edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] > b[2];
    });

    vector<vector<long long>> upgraded_edges;
    for (auto& e : optional_edges) {
        upgraded_edges.push_back({e[0], e[1], e[2] * 2, e[3]});
    }

    long long low = 0;
    long long high = 1e18;
    long long answer = -1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        DSU temp_dsu(n);
        int temp_components = n;
        int used_k = 0;

        for (auto& e : must_edges) {
            if (temp_dsu.unite(e[0], e[1])) {
                temp_components--;
            }
        }

        for (auto& e : optional_edges) {
            if (e[2] >= mid) {
                if (temp_dsu.unite(e[0], e[1])) {
                    temp_components--;
                }
            }
        }

        if (temp_components == 1) {
            answer = mid;
            low = mid + 1;
            continue;
        }

        temp_dsu = DSU(n);
        temp_components = n;
        used_k = 0;

        for (auto& e : must_edges) {
            if (temp_dsu.unite(e[0], e[1])) {
                temp_components--;
            }
        }

        for (auto& e : optional_edges) {
            if (e[2] >= mid) {
                if (temp_dsu.unite(e[0], e[1])) {
                    temp_components--;
                }
            } else if (upgraded_edges[&e - &optional_edges[0]][2] >= mid) {
                if (used_k < k && temp_dsu.unite(e[0], e[1])) {
                    temp_components--;
                    used_k++;
                }
            }
        }

        if (temp_components == 1) {
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return answer;
}
